const refs = Array.isArray($json.references) ? $json.references : [];
const downloaded = [];
for (const r of refs) {
  if (!r || typeof r.url !== 'string') continue;
  const buf = await this.helpers.httpRequest({
    method: 'GET',
    url: r.url,
    encoding: 'arraybuffer',
    returnFullResponse: false,
  });
  const base64 = Buffer.from(buf).toString('base64');
  downloaded.push({ mimeType: r.mimeType || 'image/png', data: base64 });
}
return [{ json: { ...$json, refsBase64: downloaded } }];

const upstream = $('Vertex Gemini 3.1 Image').first().json;

function readConfigNode(nodeName) {
  try {
    const item = $(nodeName).first().json;
    return item?.source ? item : null;
  } catch (error) {
    return null;
  }
}

function asObject(value) {
  return value && typeof value === 'object' && !Array.isArray(value) ? value : null;
}

function asArray(value) {
  return Array.isArray(value) ? value : [];
}

function firstString(...values) {
  for (const value of values) {
    if (typeof value === 'string' && value.trim()) return value.trim();
  }
  return '';
}

function collectParts(response) {
  const candidates = asArray(response?.candidates);
  const parts = [];

  for (const candidate of candidates) {
    parts.push(...asArray(candidate?.content?.parts));
    parts.push(...asArray(candidate?.content?.role?.parts));
  }

  parts.push(...asArray(response?.content?.parts));
  parts.push(...asArray(response?.parts));

  return parts.filter(Boolean);
}

function readInlineData(part) {
  const inlineData = asObject(part?.inlineData) || asObject(part?.inline_data);
  if (!inlineData) return null;

  const rawData = firstString(inlineData.data, inlineData.imageBase64, inlineData.base64);
  if (!rawData) return null;

  const dataUrlMatch = rawData.match(/^data:([^;]+);base64,(.+)$/);
  const mimeType = firstString(
    inlineData.mimeType,
    inlineData.mime_type,
    dataUrlMatch?.[1],
    'image/png',
  );
  const imageBase64 = (dataUrlMatch?.[2] || rawData).replace(/\s+/g, '');

  return { mimeType, imageBase64 };
}

function isProbablyBase64(value) {
  return /^[A-Za-z0-9+/]+={0,2}$/.test(value) && value.length % 4 === 0;
}

function extensionFromMime(mimeType) {
  if (mimeType.includes('jpeg') || mimeType.includes('jpg')) return 'jpg';
  if (mimeType.includes('webp')) return 'webp';
  return 'png';
}

const sourceItem = readConfigNode('Webhook Config') || readConfigNode('Manual Config') || {};
const parts = collectParts(upstream);
const imagePart = parts.find((part) => readInlineData(part));
const textPart = parts.find((part) => typeof part?.text === 'string' && part.text.trim());

if (!imagePart) {
  const candidateCount = asArray(upstream?.candidates).length;
  const partKeys = parts.map((part) => Object.keys(asObject(part) || {}).join('|')).filter(Boolean);
  throw new Error(
    'Tidak ada inline image dari Gemini response. candidates=' + candidateCount +
    '; parts=' + parts.length +
    '; partKeys=' + (partKeys.join(', ') || 'none') +
    '. Pastikan responseModalities berisi IMAGE dan model mendukung image output.'
  );
}

const inline = readInlineData(imagePart);
if (!inline?.imageBase64) {
  throw new Error('Inline image ditemukan, tetapi field data/base64 kosong.');
}

if (!isProbablyBase64(inline.imageBase64)) {
  throw new Error('Inline image data bukan base64 valid. Cek output Gemini/HTTP node.');
}

const imageBytes = Buffer.from(inline.imageBase64, 'base64');
if (!imageBytes.length) {
  throw new Error('Inline image base64 valid tetapi menghasilkan file kosong.');
}

const mimeType = inline.mimeType;
const extension = extensionFromMime(mimeType);
const requestId = firstString(sourceItem.requestId, $execution.id, Date.now().toString());

return [{
  json: {
    ok: true,
    model: 'gemini-3.1-flash-image-preview',
    mimeType,
    imageBase64: inline.imageBase64,
    imageSizeBytes: imageBytes.length,
    text: textPart?.text ?? '',
    source: sourceItem.source || 'manual',
    requestId,
    aspectRatio: sourceItem.aspectRatio || '1:1',
    userEmail: sourceItem.userEmail || null,
  },
  binary: {
    image: {
      data: inline.imageBase64,
      mimeType,
      fileName: 'gemini-3-1-output-' + requestId + '.' + extension,
      fileExtension: extension,
      fileSize: imageBytes.length,
    },
  },
}];
